display:none; position:fixed; inset:0; z-index:999999;
                                            background:rgba(0,0,0,.7); backdrop-filter:blur(4px);
                                            align-items:center; justify-content:center; flex-direction:column;

div.script:
//
    // ── Modal helpers ────────────────────────────────────────────────
    function kualeOpenModal(modalEl) {
        modalEl.style.display = 'flex';
        modalEl.style.alignItems = window.innerWidth <= 767 ? 'flex-end' : 'center';
        document.body.classList.add('kuale-modal-open');
    }
    function kualeCloseModal(modalEl) {
        modalEl.style.display = 'none';
        modalEl.style.alignItems = 'center';
        document.body.classList.remove('kuale-modal-open');
    }

    document.addEventListener('touchmove', function(e) {
        if (!document.body.classList.contains('kuale-modal-open')) return;
        var el = e.target;
        while (el && el !== document.body) {
            if (el.scrollHeight > el.clientHeight) return;
            el = el.parentElement;
        }
        e.preventDefault();
    }, { passive: false });

    document.addEventListener("DOMContentLoaded", function () {

        // ── Helper JSON local ────────────────────────────────────────
        function getSatData(key) {
            return new Promise(function(resolve, reject) {
                if (key !== 'umf' && window._satData && window._satData[key]) { resolve(window._satData[key]); return; }
                if (!window._satData) window._satData = {};
                fetch('/reclutamiento__kuale/static/src/data/' + key + '.json')
                    .then(function(r) { return r.json(); })
                    .then(function(data) { window._satData[key] = data; resolve(data); })
                    .catch(reject);
            });
        }

        // ── Autocomplete CP genérico ─────────────────────────────────
        function initCpAutocomplete(cfg) {
            var postalInput    = document.getElementById(cfg.postalId);
            var stateInput     = document.getElementById(cfg.stateId);
            var munInput       = document.getElementById(cfg.munId);
            var colonyHidden   = document.getElementById(cfg.colonyHiddenId);
            var colonyInput    = document.getElementById(cfg.colonyInputId);
            var colonyMenu     = document.getElementById(cfg.colonyMenuId);
            var colonyNotFound = document.getElementById(cfg.colonyNotFoundId);
            if (!postalInput) return;
            var allColonias = [];

            function buildMenu(filter) {
                if (!colonyMenu) return;
                colonyMenu.innerHTML = '';
                var filtered = filter
                    ? allColonias.filter(function(c) { return c.toLowerCase().indexOf(filter.toLowerCase()) !== -1; })
                    : allColonias;
                if (colonyNotFound) colonyNotFound.style.display = (filter && filtered.length === 0) ? 'block' : 'none';
                if (filtered.length === 0) { colonyMenu.style.display = 'none'; return; }
                filtered.forEach(function(nombre) {
                    (function(text) {
                        var opt = document.createElement('div');
                        opt.textContent = text;
                        opt.style.cssText = 'padding:10px 14px; cursor:pointer; font-size:14px;';
                        opt.addEventListener('mouseenter', function() { opt.style.background = '#f5f5f5'; });
                        opt.addEventListener('mouseleave', function() { opt.style.background = ''; });
                        opt.addEventListener('mousedown', function(e) {
                            e.preventDefault();
                            if (colonyInput)  colonyInput.value  = text;
                            if (colonyHidden) colonyHidden.value = text;
                            colonyMenu.style.display = 'none';
                            if (colonyNotFound) colonyNotFound.style.display = 'none';
                        });
                        colonyMenu.appendChild(opt);
                    })(nombre);
                });
                colonyMenu.style.display = 'block';
            }

            if (colonyInput) {
                colonyInput.addEventListener('input', function() {
                    if (colonyHidden) colonyHidden.value = colonyInput.value;
                    if (allColonias.length) buildMenu(colonyInput.value);
                });
                colonyInput.addEventListener('focus', function() {
                    if (allColonias.length) buildMenu(colonyInput.value);
                });
                colonyInput.addEventListener('blur', function() {
                    setTimeout(function() { if (colonyMenu) colonyMenu.style.display = 'none'; }, 150);
                    if (colonyInput.value && colonyHidden) colonyHidden.value = colonyInput.value;
                });
            }

            function buscarCP(cp) {
                if (cp.length !== 5) {
                    if (stateInput)     stateInput.value = '';
                    if (munInput)       munInput.value   = '';
                    if (colonyHidden)   colonyHidden.value = '';
                    if (colonyInput)    colonyInput.value  = '';
                    if (colonyMenu)     colonyMenu.style.display = 'none';
                    if (colonyNotFound) colonyNotFound.style.display = 'none';
                    allColonias = []; return;
                }
                getSatData('cp_estado_municipio').then(function(cpData) {
                    var entry = cpData[cp];
                    if (!entry) return;
                    var stateCode = entry.e;
                    var munCode   = entry.m;
                    Promise.all([getSatData('estados'), getSatData('municipios')]).then(function(res) {
                        if (stateInput && !stateInput.value) {
                            var est = res[0].find(function(e) { return e.c === stateCode; });
                            if (est) stateInput.value = est.n;
                        }
                        if (munInput && !munInput.value) {
                            var muns = res[1][stateCode] || [];
                            var mun  = muns.find(function(m) { return m.c === munCode; });
                            if (mun) munInput.value = mun.n;
                        }
                    });
                    getSatData('colonias').then(function(coloniasData) {
                        allColonias = coloniasData[cp] || [];
                        var currentVal = colonyInput ? colonyInput.value : '';
                        if (!currentVal) {
                            if (colonyHidden)   colonyHidden.value = '';
                            if (colonyInput)    colonyInput.value  = '';
                        } else {
                            if (colonyHidden) colonyHidden.value = currentVal;
                        }
                        if (colonyMenu)     colonyMenu.innerHTML = '';
                        if (colonyNotFound) colonyNotFound.style.display = 'none';
                    });
                }).catch(function(err) { console.error('Error CP:', err); });
            }

            postalInput.addEventListener('input', function() {
                var cp = postalInput.value.replace(/\D/g, '').slice(0, 5);
                postalInput.value = cp;
                buscarCP(cp);
            });

            document.addEventListener('click', function(e) {
                if (colonyMenu && colonyInput &&
                    !colonyInput.contains(e.target) && !colonyMenu.contains(e.target)) {
                    colonyMenu.style.display = 'none';
                }
            });

            setTimeout(function() {
                var cp = postalInput.value.replace(/\D/g, '').slice(0, 5);
                if (cp.length === 5) buscarCP(cp);
            }, 600);
        }

        // ── UMF automática por Colonia ──────────────
        function updateUMF(colonia) {
            var sel  = document.getElementById('medical_unity_select');
            var hint = document.getElementById('umf_hint');
            if (!sel) return;
            sel.innerHTML = '';
            if (!colonia || colonia.trim() === '') {
                sel.innerHTML = '<option value="">-- Ingresa tu colonia para ver tu UMF --</option>';
                if (hint) hint.style.display = 'none';
                return;
            }
            var coloniaNorm = colonia
                .toUpperCase()
                .normalize('NFD')
                .replace(/[\u0300-\u036f]/g, '')
                .replace(/\s+/g, ' ')
                .trim();

            getSatData('umf').then(function(umfData) {
                var umfs = umfData[coloniaNorm] || [];
                if (umfs.length === 0) {
                    sel.innerHTML = '<option value="">-- Sin UMF registrada para tu colonia --</option>';
                    if (hint) hint.style.display = 'none';
                } else {
                    sel.innerHTML = '';
                    umfs.forEach(function(u) {
                        var opt = document.createElement('option');
                        opt.value       = u.nombre_umf;
                        opt.textContent = u.nombre_umf + (u.domicilio ? ' \u2013 ' + u.domicilio : '');
                        opt.dataset.cp  = u.cp || '';
                        sel.appendChild(opt);
                    });
                    if (umfs.length === 1) sel.value = umfs[0].nombre_umf;
                    if (hint) hint.style.display = 'block';
                }
            }).catch(function(e) {
                console.error('Error cargando UMF:', e);
            });
        }

        // Calcular con la colonia que ya tiene el candidato del primer formulario
        setTimeout(function() {
            var colonyHidden = document.getElementById('colony');
            var colonyInput  = document.getElementById('colonyInput');
            var coloniaVal   = (colonyHidden && colonyHidden.value)
                            || (colonyInput  && colonyInput.value)
                            || '';
            if (coloniaVal) updateUMF(coloniaVal);
        }, 1200);

        // Actualizar UMF cuando el usuario seleccione una colonia del dropdown
        document.addEventListener('mousedown', function(e) {
            if (e.target && e.target.closest && e.target.closest('#colonyMenu')) {
                setTimeout(function() {
                    var val = document.getElementById('colony') &&
                            document.getElementById('colony').value;
                    if (val) updateUMF(val);
                }, 200);
            }
        });
        var colonyInputEl = document.getElementById('colonyInput');
        if (colonyInputEl) {
            colonyInputEl.addEventListener('blur', function() {
                if (this.value) updateUMF(this.value);
            });
        }

        initCpAutocomplete({
            postalId: 'postal_code', stateId: 'state', munId: 'municipality',
            colonyHiddenId: 'colony', colonyInputId: 'colonyInput',
            colonyMenuId: 'colonyMenu', colonyNotFoundId: 'colony_not_found'
        });
        initCpAutocomplete({
            postalId: 'postal_code_fiscal', stateId: 'state_fiscal', munId: 'municipality_fiscal',
            colonyHiddenId: 'colony_fiscal', colonyInputId: 'colonyFiscalInput',
            colonyMenuId: 'colonyFiscalMenu', colonyNotFoundId: 'colony_fiscal_not_found'
        });

        // ── NSS validación ───────────────────────────────────────────────
        function validateNss(nss) {
            if (nss.length !== 11 || isNaN(nss)) return false;
            var sum = 0, double = false;
            for (var i = nss.length - 1; i >= 0; i--) {
                var digit = parseInt(nss[i], 10);
                if (double) { digit *= 2; if (digit > 9) digit -= 9; }
                sum += digit;
                double = !double;
            }
            return sum % 10 === 0;
        }

        var nssInput    = document.getElementById('social_security_number');
        var nssErrorDiv = document.createElement('div');
        nssErrorDiv.style.cssText = 'color:#6c757d; font-size:13px; display:none; margin-top:4px;';
        if (nssInput) {
            nssInput.parentNode.appendChild(nssErrorDiv);
            nssInput.addEventListener('input', function () {
                this.value = this.value.replace(/\D/g, '').slice(0, 11);
                if (this.value.length === 0) { nssErrorDiv.style.display = 'none'; return; }
                if (!validateNss(this.value)) {
                    nssErrorDiv.textContent = 'NSS inválido. Debe ser un número de 11 dígitos.';
                    nssErrorDiv.style.display = 'block';
                } else {
                    nssErrorDiv.style.display = 'none';
                }
            });
        }

        // ── Otra nacionalidad ────────────────────────────────────────
        var natSel      = document.getElementById('nationality_select');
        var otherNatSec = document.getElementById('other_nationality_section');
        if (natSel) {
            natSel.addEventListener('change', function () {
                var show = this.value === 'other';
                otherNatSec.style.display = show ? 'block' : 'none';
                var on = document.getElementById('other_nationality');
                if (on) show ? on.setAttribute('required','true') : on.removeAttribute('required');
            });
        }

        // ── Alergia ──────────────────────────────────────────────────
        var allergySel    = document.getElementById('has_allergy_select');
        var allergyDetail = document.getElementById('allergy_detail_section');
        if (allergySel) {
            allergySel.addEventListener('change', function () {
                allergyDetail.style.display = this.value === 'yes' ? 'block' : 'none';
            });
        }

        // ── Tratamiento médico ───────────────────────────────────────
        var medSel    = document.getElementById('has_medical_tx_select');
        var medDetail = document.getElementById('medical_tx_detail_section');
        if (medSel) {
            medSel.addEventListener('change', function () {
                medDetail.style.display = this.value === 'yes' ? 'block' : 'none';
            });
        }

        // ── Enfermedad crónica ───────────────────────────────────────
        var chronicSel    = document.getElementById('has_chronic_disease_select');
        var chronicDetail = document.getElementById('chronic_disease_detail_section');
        if (chronicSel) {
            chronicSel.addEventListener('change', function () {
                chronicDetail.style.display = this.value === 'yes' ? 'block' : 'none';
                var cd = document.getElementById('chronic_disease');
                if (cd) this.value === 'yes' 
                    ? cd.setAttribute('required','true') 
                    : cd.removeAttribute('required');
            });
        }

        // ── Badge de usuario ─────────────────────────────────────────
        var badge = document.getElementById('kualeUserBadge');
        if (badge) {
            badge.addEventListener('click', function(e) {
                e.stopPropagation();
                this.classList.toggle('is-open');
            });
            document.addEventListener('click', function() {
                badge.classList.remove('is-open');
            });
        }

        // ── Modal alertModal (campos requeridos) ─────────────────────
        var acceptBtn = document.getElementById('acceptAlertModal');
        if (acceptBtn) {
            acceptBtn.addEventListener('click', function() {
                var modal = document.getElementById('alertModal');
                if (typeof bootstrap !== 'undefined' && bootstrap.Modal.getInstance(modal)) {
                    bootstrap.Modal.getInstance(modal).hide();
                } else {
                    modal.classList.remove('show');
                    modal.style.display = 'none';
                    document.body.classList.remove('modal-open');
                    var backdrop = document.querySelector('.modal-backdrop');
                    if (backdrop) backdrop.remove();
                }
            });
        }

        // ════════════════════════════════════════
        // CUENTAS BANCARIAS
        // ════════════════════════════════════════
        var bankModal      = document.getElementById('bankModal');
        var btnAddBank     = document.getElementById('btn_add_bank');
        var btnDeleteBank  = document.getElementById('btn_delete_bank');
        var saveBankBtn    = document.getElementById('save_bank');
        var cancelBankBtn  = document.getElementById('cancel_bank');
        var bankTbody      = document.getElementById('bank_tbody');
        var bankHidden     = document.getElementById('bank_hidden_inputs');
        var bankFilled     = document.getElementById('bank_filled');
        var bankEditIdx    = document.getElementById('bank_editing_index');
        var modalAccNum    = document.getElementById('modal_account_number');
        var modalClabe     = document.getElementById('modal_interbank_clabe');
        var bankModalTitle = document.getElementById('bank_modal_title');
        var modalBankName   = document.getElementById('modal_bank_name');
        var modalPayroll    = document.getElementById('modal_payroll_card');
        var banks          = [];

        function openBankModal(idx) {
            modalAccNum.value   = '';
            modalClabe.value    = '';
            modalBankName.value = '';
            modalPayroll.value  = '';
            [modalAccNum, modalClabe, modalBankName].forEach(function(el) {
                el.style.borderColor = '';
            });
            bankEditIdx.value = idx !== undefined ? idx : -1;
            if (idx !== undefined) {
                bankModalTitle.textContent = 'Editar cuenta bancaria';
                modalAccNum.value   = banks[idx].account_number;
                modalClabe.value    = banks[idx].interbank_clabe;
                modalBankName.value = banks[idx].bank || '';
                modalPayroll.value  = banks[idx].payroll_card_number || '';
            } else {
                bankModalTitle.textContent = 'Agregar cuenta bancaria';
            }
            kualeOpenModal(bankModal);
        }

        function closeBankModal() {
            kualeCloseModal(bankModal);
        }

        function renderBankTable() {
            bankTbody.innerHTML  = '';
            bankHidden.innerHTML = '';
            if (banks.length === 0) {
                var tr = document.createElement('tr');
                tr.innerHTML = '<td colspan="3" style="text-align:center; padding:16px; color:#aaa; font-style:italic;">Sin cuentas agregadas</td>';
                bankTbody.appendChild(tr);
                btnDeleteBank.style.display = 'none';
                bankFilled.value = '';
                bankFilled.dispatchEvent(new Event('change', {bubbles: true}));
                return;
            }
            banks.forEach(function(b, i) {
                var idx = i + 1;
                var tr = document.createElement('tr');
                tr.style.cssText = 'border-bottom:1px solid #eee; cursor:pointer;';
                tr.setAttribute('data-index', i);
                tr.innerHTML =
                    '<td style="text-align:center; padding:8px 12px;">' +
                        '<input type="checkbox" class="bank-check" data-index="' + i + '" ' +
                        'style="width:15px;height:15px;cursor:pointer;accent-color:#FA0000"/>' +
                    '</td>' +
                    '<td style="text-align:center; padding:8px 12px;">' + (b.account_number || '-') + '</td>' +
                    '<td style="text-align:center; padding:8px 12px;">' + (b.interbank_clabe  || '-') + '</td>';
                tr.addEventListener('click', function(e) {
                    if (e.target.classList.contains('bank-check')) return;
                    openBankModal(i);
                });
                bankTbody.appendChild(tr);
                // Hidden inputs — incluye todos los campos
                bankHidden.innerHTML +=
                    '<input type="hidden" name="account_number' + idx + '" value="' + (b.account_number || '') + '"/>' +
                    '<input type="hidden" name="interbank_clabe' + idx + '" value="' + (b.interbank_clabe || '') + '"/>' +
                    '<input type="hidden" name="bank' + idx + '" value="' + (b.bank || '') + '"/>' +
                    '<input type="hidden" name="payroll_card_number' + idx + '" value="' + (b.payroll_card_number || '') + '"/>' +
                    '<input type="hidden" name="account_type' + idx + '" value="nomina"/>';
            });
            bankFilled.value = 'filled';
            bankFilled.dispatchEvent(new Event('change', {bubbles: true}));
            updateBankDeleteBtn();
        }

        function updateBankDeleteBtn() {
            var checked = bankTbody.querySelectorAll('.bank-check:checked');
            btnDeleteBank.style.display = checked.length > 0 ? 'block' : 'none';
        }

        bankTbody.addEventListener('change', function(e) {
            if (e.target.classList.contains('bank-check')) updateBankDeleteBtn();
        });

        btnAddBank.addEventListener('click', function() {
            if (banks.length >= 2) { alert('Máximo 2 cuentas bancarias.'); return; }
            openBankModal();
        });

        cancelBankBtn.addEventListener('click', closeBankModal);
        bankModal.addEventListener('click', function(e) {
            if (e.target === bankModal) closeBankModal();
        });

        saveBankBtn.addEventListener('click', function() {
            var valid    = true;
            var accVal   = modalAccNum.value.replace(/\D/g, '');
            var clabeVal = modalClabe.value.replace(/\D/g, '');
            var bankVal  = modalBankName.value.trim();

            if (accVal.length !== 10) {
                modalAccNum.style.setProperty('border', '2px solid #FA0000', 'important');
                valid = false;
            } else {
                modalAccNum.style.setProperty('border', '1px solid #ced4da', 'important');
            }
            if (clabeVal.length !== 18) {
                modalClabe.style.setProperty('border', '2px solid #FA0000', 'important');
                valid = false;
            } else {
                modalClabe.style.setProperty('border', '1px solid #ced4da', 'important');
            }
            if (!bankVal) {
                modalBankName.style.setProperty('border', '2px solid #FA0000', 'important');
                valid = false;
            } else {
                modalBankName.style.setProperty('border', '1px solid #ced4da', 'important');
            }
            if (!valid) return;

            var entry = {
                account_number:      accVal,
                interbank_clabe:     clabeVal,
                bank:                bankVal,
                payroll_card_number: modalPayroll.value.replace(/\D/g, '').slice(0, 16),
                account_type:        'nomina',
            };
            var idx = parseInt(bankEditIdx.value);
            if (idx >= 0) { banks[idx] = entry; } else { banks.push(entry); }
            renderBankTable();
            closeBankModal();
        });

        // Máscara tarjeta nómina (16 dígitos)
        if (modalPayroll) {
            modalPayroll.addEventListener('input', function() {
                this.value = this.value.replace(/\D/g, '').slice(0, 16);
            });
        }

        btnDeleteBank.addEventListener('click', function() {
            var checked  = bankTbody.querySelectorAll('.bank-check:checked');
            var toDelete = [];
            checked.forEach(function(cb) { toDelete.push(parseInt(cb.getAttribute('data-index'))); });
            toDelete.sort(function(a,b){return b-a;});
            toDelete.forEach(function(i) { banks.splice(i, 1); });
            renderBankTable();
        });

        renderBankTable();

        // ════════════════════════════════════════
        // BENEFICIARIOS
        // ════════════════════════════════════════
        var beneficiaryModal      = document.getElementById('beneficiaryModal');
        var btnAddBeneficiary     = document.getElementById('btn_add_beneficiary');
        var btnDeleteBeneficiary  = document.getElementById('btn_delete_beneficiary');
        var saveBeneficiaryBtn    = document.getElementById('save_beneficiary');
        var cancelBeneficiaryBtn  = document.getElementById('cancel_beneficiary');
        var beneficiaryTbody      = document.getElementById('beneficiary_tbody');
        var beneficiaryHidden     = document.getElementById('beneficiary_hidden_inputs');
        var beneficiaryFilled     = document.getElementById('beneficiary_filled');
        var beneficiaryEditIdx    = document.getElementById('beneficiary_editing_index');
        var modalBenName          = document.getElementById('modal_beneficiary_name');
        var modalBenRel           = document.getElementById('modal_beneficiary_relationship');
        var modalBenPct           = document.getElementById('modal_beneficiary_percentage');
        var modalOtherRelSec      = document.getElementById('modal_other_rel_section');
        var modalOtherRel         = document.getElementById('modal_other_relationship');
        var modalBenTitle         = document.getElementById('beneficiary_modal_title');
        var pctWarning            = document.getElementById('beneficiary_percentage_warning');
        var beneficiaries         = [];

        var RELATIONSHIP_LABELS = {
            mother: 'Madre', father: 'Padre', sibling: 'Hermano(a)',
            child: 'Hijo(a)', spouse: 'Cónyuge', other: 'Otro'
        };

        modalBenRel.addEventListener('change', function() {
            modalOtherRelSec.style.display = this.value === 'other' ? 'block' : 'none';
            if (this.value !== 'other') modalOtherRel.value = '';
        });

        function openBeneficiaryModal(idx) {
            modalBenName.value  = '';
            modalBenRel.value   = '';
            modalBenPct.value   = '';
            modalOtherRel.value = '';
            modalOtherRelSec.style.display = 'none';
            pctWarning.style.display = 'none';
            [modalBenName, modalBenRel, modalBenPct, modalOtherRel].forEach(function(el) { el.style.borderColor = ''; });
            beneficiaryEditIdx.value = idx !== undefined ? idx : -1;
            if (idx !== undefined) {
                modalBenTitle.textContent = 'Editar beneficiario';
                var b = beneficiaries[idx];
                modalBenName.value  = b.name;
                modalBenRel.value   = b.relationship;
                modalBenPct.value   = b.percentage;
                modalOtherRel.value = b.other_relationship || '';
                modalOtherRelSec.style.display = b.relationship === 'other' ? 'block' : 'none';
            } else {
                modalBenTitle.textContent = 'Agregar beneficiario';
                var usedPct = beneficiaries.reduce(function(s,b){ return s + parseFloat(b.percentage||0); }, 0);
                modalBenPct.value = Math.max(0, 100 - usedPct);
            }
            kualeOpenModal(beneficiaryModal);
        }

        function closeBeneficiaryModal() {
            kualeCloseModal(beneficiaryModal);
        }

        function renderBeneficiaryTable() {
            beneficiaryTbody.innerHTML  = '';
            beneficiaryHidden.innerHTML = '';
            if (beneficiaries.length === 0) {
                var tr = document.createElement('tr');
                tr.innerHTML = '<td colspan="4" style="text-align:center; padding:16px; color:#aaa; font-style:italic;">Sin beneficiarios agregados</td>';
                beneficiaryTbody.appendChild(tr);
                btnDeleteBeneficiary.style.display = 'none';
                beneficiaryFilled.value = '';
                beneficiaryFilled.dispatchEvent(new Event('change', {bubbles: true}));
                return;
            }
            beneficiaries.forEach(function(b, i) {
                var idx = i + 1;
                var relLabel = b.relationship === 'other'
                    ? (b.other_relationship || 'Otro')
                    : (RELATIONSHIP_LABELS[b.relationship] || b.relationship);
                var tr = document.createElement('tr');
                tr.style.cssText = 'border-bottom:1px solid #eee; cursor:pointer;';
                tr.setAttribute('data-index', i);
                tr.innerHTML =
                    '<td style="text-align:center; padding:8px 12px;">' +
                        '<input type="checkbox" class="beneficiary-check" data-index="' + i + '" ' +
                        'style="width:15px;height:15px;cursor:pointer;accent-color:#FA0000"/>' +
                    '</td>' +
                    '<td style="text-align:center; padding:8px 12px;">' + (b.name || '-') + '</td>' +
                    '<td style="text-align:center; padding:8px 12px;">' + relLabel + '</td>' +
                    '<td style="text-align:center; padding:8px 12px;">' + (b.percentage || '0') + '%</td>';
                tr.addEventListener('click', function(e) {
                    if (e.target.classList.contains('beneficiary-check')) return;
                    openBeneficiaryModal(i);
                });
                beneficiaryTbody.appendChild(tr);
                beneficiaryHidden.innerHTML +=
                    '<input type="hidden" name="beneficiary_name' + idx + '" value="' + (b.name || '') + '"/>' +
                    '<input type="hidden" name="beneficiary_relationship' + idx + '" value="' + (b.relationship || '') + '"/>' +
                    '<input type="hidden" name="other_relationship' + idx + '" value="' + (b.other_relationship || '') + '"/>' +
                    '<input type="hidden" name="beneficiary_percentage' + idx + '" value="' + (b.percentage || '') + '"/>';
            });
            beneficiaryFilled.value = 'filled';
            beneficiaryFilled.dispatchEvent(new Event('change', {bubbles: true}));
            updateBeneficiaryDeleteBtn();
        }

        function updateBeneficiaryDeleteBtn() {
            var checked = beneficiaryTbody.querySelectorAll('.beneficiary-check:checked');
            btnDeleteBeneficiary.style.display = checked.length > 0 ? 'block' : 'none';
        }

        beneficiaryTbody.addEventListener('change', function(e) {
            if (e.target.classList.contains('beneficiary-check')) updateBeneficiaryDeleteBtn();
        });

        btnAddBeneficiary.addEventListener('click', function() {
            if (beneficiaries.length >= 4) { alert('Máximo 4 beneficiarios.'); return; }
            openBeneficiaryModal();
        });

        cancelBeneficiaryBtn.addEventListener('click', closeBeneficiaryModal);
        beneficiaryModal.addEventListener('click', function(e) {
            if (e.target === beneficiaryModal) closeBeneficiaryModal();
        });

        saveBeneficiaryBtn.addEventListener('click', function() {
            var valid = true;
            pctWarning.style.display = 'none';

            if (!modalBenName.value.trim()) {
                modalBenName.style.setProperty('border', '2px solid #FA0000', 'important');
                valid = false;
            } else {
                modalBenName.style.setProperty('border', '1px solid #ced4da', 'important');
            }
            if (!modalBenRel.value) {
                modalBenRel.style.setProperty('border', '2px solid #FA0000', 'important');
                valid = false;
            } else {
                modalBenRel.style.setProperty('border', '1px solid #ced4da', 'important');
            }
            if (!modalBenPct.value || parseFloat(modalBenPct.value) <= 0) {
                modalBenPct.style.setProperty('border', '2px solid #FA0000', 'important');
                valid = false;
            } else {
                modalBenPct.style.setProperty('border', '1px solid #ced4da', 'important');
            }
            if (modalBenRel.value === 'other' && !modalOtherRel.value.trim()) {
                modalOtherRel.style.setProperty('border', '2px solid #FA0000', 'important');
                valid = false;
            } else {
                modalOtherRel.style.setProperty('border', '1px solid #ced4da', 'important');
            }
            if (!valid) return;

            var editIdx = parseInt(beneficiaryEditIdx.value);
            var usedPct = beneficiaries.reduce(function(s, b, i) {
                return editIdx === i ? s : s + parseFloat(b.percentage || 0);
            }, 0);
            var newPct = parseFloat(modalBenPct.value || 0);
            if (usedPct + newPct > 100) {
                pctWarning.style.display = 'block';
                pctWarning.textContent = 'La suma de porcentajes no puede exceder 100%. Disponible: ' + (100 - usedPct) + '%';
                return;
            }
            var entry = {
                name:               modalBenName.value.trim(),
                relationship:       modalBenRel.value,
                other_relationship: modalBenRel.value === 'other' ? modalOtherRel.value.trim() : '',
                percentage:         modalBenPct.value
            };
            if (editIdx >= 0) { beneficiaries[editIdx] = entry; } else { beneficiaries.push(entry); }
            renderBeneficiaryTable();
            closeBeneficiaryModal();
        });

        btnDeleteBeneficiary.addEventListener('click', function() {
            var checked  = beneficiaryTbody.querySelectorAll('.beneficiary-check:checked');
            var toDelete = [];
            checked.forEach(function(cb) { toDelete.push(parseInt(cb.getAttribute('data-index'))); });
            toDelete.sort(function(a,b){return b-a;});
            toDelete.forEach(function(i) { beneficiaries.splice(i, 1); });
            renderBeneficiaryTable();
        });

        renderBeneficiaryTable();

        if (modalAccNum) modalAccNum.addEventListener('input', function() {
            this.value = this.value.replace(/\D/g, '').slice(0, 10);
        });
        if (modalClabe) modalClabe.addEventListener('input', function() {
            this.value = this.value.replace(/\D/g, '').slice(0, 18);
        });

        // ── Checkbox términos y condiciones ──────────────────────────
        var termsLabel  = document.getElementById('terms_label');
        var termsCb     = document.getElementById('terms_conditions');
        var termsCustom = document.getElementById('terms_custom_check');

        function updateTermsVisual() {
            if (termsCb.checked) {
                termsCustom.style.background    = '#FA0000';
                termsCustom.style.setProperty('border', '2px solid #FA0000', 'important');
                termsCustom.innerHTML = '<svg width="12" height="12" viewBox="0 0 12 12" fill="none"><polyline points="1,6 4,9 11,2" stroke="#fff" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/></svg>';
            } else {
                termsCustom.style.background  = '#fff';
                termsCustom.style.setProperty('border', '2px solid #ccc', 'important');
                termsCustom.innerHTML = '';
            }
        }

        if (termsLabel) {
            termsLabel.addEventListener('click', function(e) {
                if (e.target.id === 'open_terms_modal') return;
                termsCb.checked = !termsCb.checked;
                updateTermsVisual();
            });
        }

        // ── Modal términos y condiciones ─────────────────────────────
        var termsModal    = document.getElementById('termsModal');
        var openTermsBtn  = document.getElementById('open_terms_modal');
        var acceptTerms   = document.getElementById('accept_terms');
        var declineTerms  = document.getElementById('decline_terms');

        if (openTermsBtn) {
            openTermsBtn.addEventListener('click', function(e) {
                e.preventDefault();
                kualeOpenModal(termsModal);
            });
        }
        if (acceptTerms) {
            acceptTerms.addEventListener('click', function() {
                termsCb.checked = true;
                updateTermsVisual();
                kualeCloseModal(termsModal);
            });
        }
        if (declineTerms) {
            declineTerms.addEventListener('click', function() {
                kualeCloseModal(termsModal);
            });
        }
        termsModal.addEventListener('click', function(e) {
            if (e.target === termsModal) kualeCloseModal(termsModal);
        });

        // ════════════════════════════════════════
        // CONTACTOS DE EMERGENCIA
        // ════════════════════════════════════════
        var emergencyModal     = document.getElementById('emergencyModal');
        var btnAddEmergency    = document.getElementById('btn_add_emergency');
        var saveEmergencyBtn   = document.getElementById('save_emergency');
        var cancelEmergencyBtn = document.getElementById('cancel_emergency');
        var emergencyTbody     = document.getElementById('emergency_tbody');
        var emergencyHidden    = document.getElementById('emergency_hidden_inputs');
        var emergencyFilled    = document.getElementById('emergency_filled');
        var emergencyEditIdx   = document.getElementById('emergency_editing_index');
        var modalEmgName       = document.getElementById('modal_emergency_name');
        var modalEmgRel        = document.getElementById('modal_emergency_relationship');
        var modalEmgPhone      = document.getElementById('modal_emergency_phone');
        var emergencyModalTitle= document.getElementById('emergency_modal_title');
        var emergencies        = [];

        var EMG_REL_LABELS = {
            mother: 'Madre', father: 'Padre', sibling: 'Hermano(a)',
            child: 'Hijo(a)', spouse: 'Cónyuge', other: 'Otro'
        };

        function openEmergencyModal(idx) {
            modalEmgName.value  = '';
            modalEmgRel.value   = '';
            modalEmgPhone.value = '';
            [modalEmgName, modalEmgRel, modalEmgPhone].forEach(function(el) {
                el.style.borderColor = '';
            });
            emergencyEditIdx.value = idx !== undefined ? idx : -1;
            if (idx !== undefined) {
                emergencyModalTitle.textContent = 'Editar contacto de emergencia';
                var e = emergencies[idx];
                modalEmgName.value  = e.name;
                modalEmgRel.value   = e.relationship;
                modalEmgPhone.value = e.phone_number;
            } else {
                emergencyModalTitle.textContent = 'Agregar contacto de emergencia';
            }
            kualeOpenModal(emergencyModal);
        }

        function closeEmergencyModal() {
            kualeCloseModal(emergencyModal);
        }

        function renderEmergencyTable() {
            emergencyTbody.innerHTML  = '';
            emergencyHidden.innerHTML = '';
            if (emergencies.length === 0) {
                var tr = document.createElement('tr');
                tr.innerHTML = '<td colspan="4" style="text-align:center; padding:16px; ' +
                            'color:#aaa; font-style:italic;">Sin contactos agregados</td>';
                emergencyTbody.appendChild(tr);
                emergencyFilled.value = '';
                emergencyFilled.dispatchEvent(new Event('change', {bubbles: true}));
                return;
            }
            emergencies.forEach(function(e, i) {
                var idx = i + 1;
                var relLabel = EMG_REL_LABELS[e.relationship] || e.relationship;
                var tr = document.createElement('tr');
                tr.style.cssText = 'border-bottom:1px solid #eee; cursor:pointer;';
                tr.innerHTML =
                    '<td style="text-align:center; padding:8px 12px;">' +
                        '<input type="checkbox" class="emergency-check" data-index="' + i + '" ' +
                        'style="width:15px;height:15px;cursor:pointer;accent-color:#FA0000"/>' +
                    '</td>' +
                    '<td style="text-align:center; padding:8px 12px;">' + (e.name || '-') + '</td>' +
                    '<td style="text-align:center; padding:8px 12px;">' + relLabel + '</td>' +
                    '<td style="text-align:center; padding:8px 12px;">' + (e.phone_number || '-') + '</td>';
                tr.addEventListener('click', function(ev) {
                    if (ev.target.classList.contains('emergency-check')) return;
                    openEmergencyModal(i);
                });
                emergencyTbody.appendChild(tr);
                emergencyHidden.innerHTML +=
                    '<input type="hidden" name="emergency_name' + idx + 
                    '" value="' + (e.name || '') + '"/>' +
                    '<input type="hidden" name="emergency_relationship' + idx + 
                    '" value="' + (e.relationship || '') + '"/>' +
                    '<input type="hidden" name="emergency_phone' + idx + 
                    '" value="' + (e.phone_number || '') + '"/>';
            });
            emergencyFilled.value = 'filled';
            emergencyFilled.dispatchEvent(new Event('change', {bubbles: true}));
        }

        btnAddEmergency.addEventListener('click', function() {
            openEmergencyModal();
        });

        cancelEmergencyBtn.addEventListener('click', closeEmergencyModal);
        emergencyModal.addEventListener('click', function(e) {
            if (e.target === emergencyModal) closeEmergencyModal();
        });

        saveEmergencyBtn.addEventListener('click', function() {
            var valid = true;
            if (!modalEmgName.value.trim()) {
                modalEmgName.style.setProperty('border', '2px solid #FA0000', 'important');
                valid = false;
            } else {
                modalEmgName.style.setProperty('border', '1px solid #ced4da', 'important');
            }
            if (!modalEmgRel.value) {
                modalEmgRel.style.setProperty('border', '2px solid #FA0000', 'important');
                valid = false;
            } else {
                modalEmgRel.style.setProperty('border', '1px solid #ced4da', 'important');
            }
            if (!modalEmgPhone.value.trim()) {
                modalEmgPhone.style.setProperty('border', '2px solid #FA0000', 'important');
                valid = false;
            } else {
                modalEmgPhone.style.setProperty('border', '1px solid #ced4da', 'important');
            }
            if (!valid) return;

            var entry = {
                name:         modalEmgName.value.trim(),
                relationship: modalEmgRel.value,
                phone_number: modalEmgPhone.value.trim()
            };
            var editIdx = parseInt(emergencyEditIdx.value);
            if (editIdx >= 0) { emergencies[editIdx] = entry; } 
            else { emergencies.push(entry); }
            renderEmergencyTable();
            closeEmergencyModal();
        });

        if (modalEmgPhone) {
            modalEmgPhone.addEventListener('input', function() {
                // Quitar todo lo que no sea dígito
                var digits = this.value.replace(/\D/g, '').slice(0, 10);
                // Aplicar máscara (XXX)-XXX-XXXX
                var formatted = '';
                if (digits.length === 0) {
                    formatted = '';
                } else if (digits.length <= 3) {
                    formatted = '(' + digits;
                } else if (digits.length <= 6) {
                    formatted = '(' + digits.slice(0,3) + ')-' + digits.slice(3);
                } else {
                    formatted = '(' + digits.slice(0,3) + ')-' + digits.slice(3,6) + '-' + digits.slice(6);
                }
                this.value = formatted;
            });
        }

        renderEmergencyTable();

    }); // fin DOMContentLoaded

    // ── Submit del complemento ───────────────────────────────────────
    var submitBtn = document.getElementById('complement_submit_btn');
    if (submitBtn) {
        submitBtn.addEventListener('click', function() {
            // Validar términos
            var cb = document.getElementById('terms_conditions');
            if (cb && !cb.checked) {
                var customCheck = document.getElementById('terms_custom_check');
                if (customCheck) customCheck.style.setProperty('border', '2px solid #FFA500', 'important');
                var alertModal = document.querySelector('#alertModal');
                var modalBody  = alertModal ? alertModal.querySelector('.modal-body') : null;
                if (modalBody) {
                    modalBody.innerHTML = "<p>Por favor, completa los siguientes campos antes de continuar:</p><ul style='text-align:left; margin-top:8px;'><li style='margin-bottom:4px;'><strong>Términos y condiciones</strong></li></ul>";
                }
                if (alertModal && window.$ && typeof window.$(alertModal).modal === 'function') {
                    window.$(alertModal).modal('show');
                    var acceptBtn2 = alertModal.querySelector('#acceptAlertModal');
                    if (acceptBtn2) {
                        var newBtn = acceptBtn2.cloneNode(true);
                        acceptBtn2.parentNode.replaceChild(newBtn, acceptBtn2);
                        newBtn.addEventListener('click', function() { window.$(alertModal).modal('hide'); });
                    }
                }
                cb.scrollIntoView({behavior: 'smooth', block: 'center'});
                return;
            }

            // Mostrar modal de confirmación
            var confirmModal = document.getElementById('kualeConfirmModal');
            kualeOpenModal(confirmModal);
        });
    }

    // ── Confirmación envío ───────────────────────────────────────────
    var confirmOk     = document.getElementById('kualeConfirmOk');
    var confirmCancel = document.getElementById('kualeConfirmCancel');
    var confirmModal  = document.getElementById('kualeConfirmModal');
    var loadingModal  = document.getElementById('kualeLoadingModal');

    if (confirmCancel) {
        confirmCancel.addEventListener('click', function() {
            kualeCloseModal(confirmModal);
        });
    }

    if (confirmOk) {
        confirmOk.addEventListener('click', function() {
            kualeCloseModal(confirmModal);
            kualeOpenModal(loadingModal);

            // Sincronizar colonias
            var ci = document.getElementById('colonyInput');
            var ch = document.getElementById('colony');
            if (ci && ch && ci.value) ch.value = ci.value;
            var cfi = document.getElementById('colonyFiscalInput');
            var cfh = document.getElementById('colony_fiscal');
            if (cfi && cfh && cfi.value) cfh.value = cfi.value;

            var form = document.getElementById('hr_recruitment_form2');
            var csrf = document.querySelector('input[name="csrf_token"]');
            if (!csrf) {
                var csrfInput = document.createElement('input');
                csrfInput.type  = 'hidden';
                csrfInput.name  = 'csrf_token';
                csrfInput.value = (typeof odoo !== 'undefined' && odoo.csrf_token) ? odoo.csrf_token : '';
                form.appendChild(csrfInput);
            }

            var fd = new FormData(form);
            fetch(form.action, { method: 'POST', body: fd })
                .then(function(r) { return r.json(); })
                .then(function(data) {
                    kualeCloseModal(loadingModal);
                    if (data.id) {
                        window.location.href = '/job-thank-you-c';
                    } else {
                        alert('Error al enviar. Intenta de nuevo.');
                        console.error('Error respuesta:', data);
                    }
                })
                .catch(function(err) {
                    kualeCloseModal(loadingModal);
                    console.error('Error de red:', err);
                    alert('Error de conexión. Intenta de nuevo.');
                });
        });
    }
