                            (function() {
                                document.addEventListener('DOMContentLoaded', function() {
                                    var badge = document.getElementById('kualeUserBadge');
                                    if (badge) {
                                        badge.addEventListener('click', function(e) {
                                            e.stopPropagation();
                                            this.classList.toggle('is-open');
                                        });
                                        document.addEventListener('click', function() {
                                            badge.classList.remove('is-open');
                                        });
                                    }
                                    history.pushState(null, '', window.location.href);
                                    window.addEventListener('popstate', function() {
                                        window.location.replace('/mis-aplicaciones');
                                    });

                                    // ── Contador y cierre ────────────────────────────
                                    var segundos = 10;
                                    var countEl  = document.getElementById('kuale-countdown');

                                    function tick() {
                                        if (countEl) countEl.textContent = segundos;
                                        if (segundos <= 0) {
                                            cerrarYRecargar();
                                            return;
                                        }
                                        segundos--;
                                        setTimeout(tick, 1000);
                                    }

                                    function cerrarYRecargar() {
                                        // Intentar notificar a la ventana anterior para que recargue
                                        try {
                                            if (window.opener && !window.opener.closed) {
                                                window.opener.location.reload();
                                            }
                                        } catch(e) {}
                                        window.close();
                                        // Si no se puede cerrar, redirigir
                                        setTimeout(function() {
                                            window.location.href = '/mis-aplicaciones';
                                        }, 300);
                                    }

                                    tick();
                                });
                            })();

                            (function() {
                                var canvas = document.getElementById('kuale-confetti');
                                var ctx = canvas.getContext('2d');
                                canvas.width = window.innerWidth;
                                canvas.height = window.innerHeight;
                                var pieces = [];
                                var colors = ['#FA0000','#fff','#ffcc00','#ff6600','#cc0000'];
                                for (var i = 0; i < 120; i++) {
                                    pieces.push({
                                        x: Math.random() * canvas.width,
                                        y: Math.random() * canvas.height - canvas.height,
                                        w: Math.random() * 10 + 5,
                                        h: Math.random() * 6 + 3,
                                        color: colors[Math.floor(Math.random() * colors.length)],
                                        speed: Math.random() * 3 + 2,
                                        angle: Math.random() * 360,
                                        spin: Math.random() * 4 - 2,
                                        opacity: 1
                                    });
                                }
                                var frame = 0;
                                function draw() {
                                    ctx.clearRect(0, 0, canvas.width, canvas.height);
                                    pieces.forEach(function(p) {
                                        ctx.save();
                                        ctx.translate(p.x, p.y);
                                        ctx.rotate(p.angle * Math.PI / 180);
                                        ctx.globalAlpha = p.opacity;
                                        ctx.fillStyle = p.color;
                                        ctx.fillRect(-p.w/2, -p.h/2, p.w, p.h);
                                        ctx.restore();
                                        p.y += p.speed;
                                        p.angle += p.spin;
                                        if (p.y > canvas.height) p.opacity -= 0.02;
                                    });
                                    frame++;
                                    if (frame < 300) requestAnimationFrame(draw);
                                    else ctx.clearRect(0, 0, canvas.width, canvas.height);
                                }
                                draw();
                                window.addEventListener('resize', function() {
                                    canvas.width = window.innerWidth;
                                    canvas.height = window.innerHeight;
                                });
                            })();
